    // Calculate total length L required for the formatted string
    int L = strlen(metric_name);
    if (label_count > 0) {
        L += 1; // for "{"
        for (int i = 0; i < label_count; i++) {
            if (label_keys[i] == NULL || label_values[i] == NULL) {
                return -1;
            }
            L += strlen(label_keys[i]) + strlen(label_values[i]) + 3; // for key, value, and =""
            if (i < label_count - 1) {
                L += 1; // for comma
            }
        }
        L += 1; // for "}"
    }

    // Use snprintf for metric_name with buffer size L+1
    int size = L + 1;
    int result = snprintf(metric_output, size, "%s", metric_name);
    if (result < 0) {
        return -1; // Error in snprintf
    }
    if (result >= size) {
        return -1; // Truncation occurred
    }
    written = result;

    if (label_count > 0) {
        // Append opening brace
        size = L + 1 - written;
        result = snprintf(metric_output + written, size, "{");
        if (result < 0) {
            return -1;
        }
        if (result >= size) {
            return -1;
        }
        written += result;

        for (int i = 0; i < label_count; i++) {
            // Append label key and value
            size = L + 1 - written;
            result = snprintf(metric_output + written, size, "%s=\"%s\"", label_keys[i], label_values[i]);
            if (result < 0) {
                return -1;
            }
            if (result >= size) {
                return -1;
            }
            written += result;

            // Append comma if not last label
            if (i < label_count - 1) {
                size = L + 1 - written;
                result = snprintf(metric_output + written, size, ",");
                if (result < 0) {
                    return -1;
                }
                if (result >= size) {
                    return -1;
                }
                written += result;
            }
        }

        // Append closing brace
        size = L + 1 - written;
        result = snprintf(metric_output + written, size, "}");
        if (result < 0) {
            return -1;
        }
        if (result >= size) {
            return -1;
        }
        written += result;
    }

    return written;
}
